import { createAgent, type FlueContext } from '@flue/runtime'
import * as v from 'valibot'
import { indexPdf } from '../tools/index-pdf.ts'
import { searchDocs } from '../tools/search-docs.ts'

const agent = createAgent(() => ({
  model: 'anthropic/claude-sonnet-4-6',
  instructions: 'Index the PDF if needed, then answer the question using only retrieved chunks. Cite page numbers.',
  tools: [indexPdf, searchDocs],
}))

const Answer = v.object({
  answer: v.string(),
  citations: v.array(v.object({
    page: v.number(),
    quote: v.string(),
  })),
})

export async function run({ init, payload }: FlueContext<{ url: string; question: string }>) {
  const harness = await init(agent)
  const session = await harness.session()

  const response = await session.prompt(
    `Index ${payload.url} if needed, then answer: ${payload.question}`,
    { result: Answer }
  )

  return response.data
}

import { defineTool } from '@flue/runtime'
import { extractText, getDocumentProxy } from 'unpdf'
import * as v from 'valibot'
import { chunkText, upsertChunks } from '../lib/vector-store.ts'

export const indexPdf = defineTool({
  name: 'index_pdf',
  description:
    'Downloads a PDF, splits each page into chunks, embeds them, and stores them for retrieval.',
  parameters: v.object({
    url: v.string(),
    doc: v.optional(v.string()),
  }),
  execute: async ({ url, doc }) => {
    const buffer = await fetch(url).then((r) => r.arrayBuffer())
    const pdf = await getDocumentProxy(new Uint8Array(buffer))
    const { text } = await extractText(pdf, { mergePages: false })

    const chunks = text.flatMap((pageText, i) =>
      chunkText(pageText).map((content) => ({
        doc: doc ?? url,
        page: i + 1,
        content,
      }))
    )

    await upsertChunks(chunks)
    return `Indexed ${chunks.length} chunks across ${text.length} pages.`
  },
})

import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { search } from '../lib/vector-store.ts'

export const searchDocs = defineTool({
  name: 'search_docs',
  description:
    'Retrieves the most relevant PDF chunks for a question, including the page number of each chunk for citation.',
  parameters: v.object({
    query: v.string(),
    topK: v.optional(v.number(), 5),
  }),
  execute: async ({ query, topK }) => {
    const hits = await search(query, topK)
    return JSON.stringify(hits, null, 2)
  },
})

import { openai } from '@ai-sdk/openai'
import { createClient } from '@libsql/client'
import { embed, embedMany } from 'ai'

const db = createClient({ url: process.env.LIBSQL_URL ?? 'file:pdf-index.db' })
const embeddingModel = openai.embedding('text-embedding-3-small')

export interface Chunk {
  doc: string
  page: number
  content: string
}

export function chunkText(text: string, size = 1000, overlap = 200): string[] {
  const out: string[] = []
  for (let i = 0; i < text.length; i += size - overlap) {
    const slice = text.slice(i, i + size).trim()
    if (slice) {
      out.push(slice)
    }
  }
  return out
}

async function ensureSchema(): Promise<void> {
  await db.execute(
    'CREATE TABLE IF NOT EXISTS chunks (id INTEGER PRIMARY KEY AUTOINCREMENT, doc TEXT, page INTEGER, content TEXT, embedding F32_BLOB(1536))'
  )
}

export async function upsertChunks(chunks: Chunk[]): Promise<void> {
  await ensureSchema()
  const { embeddings } = await embedMany({
    model: embeddingModel,
    values: chunks.map((c) => c.content),
  })
  for (let i = 0; i < chunks.length; i++) {
    const c = chunks[i]
    await db.execute({
      sql: 'INSERT INTO chunks (doc, page, content, embedding) VALUES (?, ?, ?, vector32(?))',
      args: [c.doc, c.page, c.content, JSON.stringify(embeddings[i])],
    })
  }
}

export async function search(query: string, topK: number) {
  await ensureSchema()
  const { embedding } = await embed({ model: embeddingModel, value: query })
  const result = await db.execute({
    sql: 'SELECT doc, page, content, vector_distance_cos(embedding, vector32(?)) AS distance FROM chunks ORDER BY distance ASC LIMIT ?',
    args: [JSON.stringify(embedding), topK],
  })
  return result.rows
}
